            's.cta_section.1': '<h2 data-i18n-html="s.cta.h2">Не от понеделник.<br/><em class="purple">Днес.</em></h2> <p style="color:#888; max-width:480px; margin:0 auto 32px;">         Имаш знанието. Имаш плана. Имаш числата.<br/>         Единственото, което липсва — е <strong>решението</strong>.     </p> <a class="btn btn-purple" href="#" onclick="document.querySelector(\'.accordion-item.purple .accordion-header\').click(); window.scrollTo({top: document.querySelector(\'.accordion-item.purple\').offsetTop - 80, behavior:\'smooth\'}); return false;"> <span data-i18n="s.cta.btn">Започни Ден 1 →</span> </a>',
