            'm.stat_card.1': '<div class="stat-number">2000</div> <div class="stat-label">High risk. Equivalent to "I don\'t get out of my chair".</div>',
            'm.stat_card.2': '<div class="stat-number">5000</div> <div class="stat-label">Minimum. −40% overall mortality.</div>',
            'm.stat_card.3': '<div class="stat-number">8000+</div> <div class="stat-label">Optimally. −60% cardiac risk.</div>',
            'm.stat_box.1': '<div class="stat-number">150 min</div> <div class="stat-label" data-i18n="m.hero.stat">per week = −33% risk of early death = only 21 min/day</div>',
            'm.info_box.1': '<h3>💡 Recommendation</h3> <p style="margin-top:8px;">2× strength + 2× HIIT + walking every day. That\'s all.</p>',
            'm.info_box.2': '<h3>💡 With these 4 devices you cover:</h3> <p style="margin-top:8px;">Full Upper · Full Lower · Abs · Cardio (HIIT) · Stretching</p> <p style="margin-top:8px; color:var(--muted);">Total investment: ~100 BGN. Fitness subscription: ~50 BGN/month. They pay for 2 months — and then you train for free forever.</p>',
            'm.info_box.3': '<h3>Try</h3> <p style="margin-top:8px;">first Don\'t think about a fitness program. Make <strong>10 minutes walking + 10 chair squats + 20 seconds plank</strong>. If this happens today, the page has done its job.</p>',
            'm.info_box.4': '<h3>When it\'s not "it\'ll just pass"</h3> <p style="margin-top:8px;">If you have numbness, weakness in the leg, swelling, locking of the knee, pain at night or pain after an injury, do not rely on a site. I need an orthopedist, neurologist or kinesitherapist.</p>',
            'm.info_box.5': '<h3>Steps calculator</h3> <input data-fn="updateSteps" data-output="steps-output" max="15000" min="500" step="500" type="range" value="5000"/> <div id="steps-output"></div>',
            'm.cta_section.1': '<h2>The minimum:<em class="green">30 min per day</em></h2> <p style="color:#888; max-width:480px; margin:0 auto 24px;">Not 2 hours. Not 6 times a week. 30 minutes. Every day.</p> <div class="cta-steps"> <div class="cta-step"> <div class="step-num">1</div> <span>10 min walk in the morning</span> </div> <div class="cta-step"> <div class="step-num">2</div> <span>10 min exercises (squats, facelifts, plank)</span> </div> <div class="cta-step"> <div class="step-num">3</div> <span>10 min walk in the evening</span> </div> </div> <a class="btn btn-green" href="eat.html">See what to eat →</a> ',
