            'c.cta_section.1': '<h2>You have the numbers.<br/><em class="green">Get the plan.</em></h2> <p style="color:#888; margin-bottom:24px;">7 days. Specific meals. A specific movement. Free of charge.</p> <a class="btn btn-green" href="start.html">Get the plan →</a> ',
